import Logo from '../../logo.png';
import './header.css';

const Header = () => {
    return(
        <>
            <div className='col-2'>
                <img src={Logo} className="App-logo" alt="logo"></img>
            </div>
            <div className='col-8'>
                <h1>NPTFC Tigers U9 23-24</h1>
            </div>
        </>
    );
}

export default Header;
